import sqlite3

def check_login(username, password):
    # Assume connection to a legacy database named 'legacy_users.db'
    conn = sqlite3.connect('legacy_users.db')
    cursor = conn.cursor()
    
    query = "SELECT COUNT(1) FROM users WHERE username = ? AND password = ?"
    cursor.execute(query, (username, password))
    result = cursor.fetchone()
    
    conn.close()

    return result[0] == 1

